import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './SignIn.css';

function SignIn() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate();

    const handleSignIn = () => {
        // Here, you would typically make an API call to verify the user's credentials.
        // For simplicity, we'll just check if the email and password are not empty.
        if (email && password) {
            // If the credentials are valid, store the user in local storage and navigate to the home page.
            const user = { email, username: email.split('@')[0] };
            localStorage.setItem('user', JSON.stringify(user));
            navigate('/');
        } else {
            alert('Please enter a valid email and password.');
        }
    };

    return (
        <div className="signin-container">
            <h2>Sign In</h2>
            <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
            />
            <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
            />
            <button onClick={handleSignIn}>Sign In</button>
            <p>
                Don't have an account? <span onClick={() => navigate('/signup')}>Sign Up</span>
            </p>
        </div>
    );
}

export default SignIn;
